            EntityMWebviewPanelMissionPage = Deserialize<EntityMWebviewPanelMissionPage>(masterDataPath, "EntityMWebviewPanelMissionPageTable.json"),
            EntityMWebviewPanelMission = Deserialize<EntityMWebviewPanelMission>(masterDataPath, "EntityMWebviewPanelMissionTable.json")
        };
    }

    private static List<T> Deserialize<T>(string basePath, string fileName)
    {
        var path = Path.Combine(basePath, fileName);
        if (!File.Exists(path)) return [];
        return JsonSerializer.Deserialize<List<T>>(File.ReadAllText(path), JsonOptions) ?? [];
    }
}
